const listaImagens = [
  "./img/im4.jpg",
  "./img/im5.png",
  "./img/im6.jpg",
  "./img/im17.jpg",
  "./img/im19.jpg",
  "./img/im10.jpg",
  "./img/im18.jpg",
  "./img/im14.jpg",
];

let baralho = [];
let cartaSelecionada1 = null;
let cartaSelecionada2 = null;
let tabuleiroTravado = false;
let totalJogadas = 0;
let paresEncontrados = 0;
const totalPares = listaImagens.length;

// ----- Variáveis do cronômetro ------
let segundosDecorridos = 0;
let idIntervaloTempo = null;

const somInicio = new Audio(
  "data:audio/wav;base64,",
);
const somVitoria = new Audio(
  "data:audio/wav;base64,",
);

// ----- Mensagens exibidas a cada jogada -----
const mensagensAcerto = [
  "Mandou bem! 🔥",
  "Fez o mais difícil 😤👏",
  "Não tem pra ninguém!",
  "Memória de elefante 🐘",
  "Combo confirmado ✅",
  "Tá voando hoje 🚀",
];

const mensagensErroPerto = [
  "Tava do lado bb 😩",
  "Quase! Tava colado ali 👀",
  "Por um triz... tava do lado",
];

const mensagensErroLonge = [
  "Perdeu aura 💀",
  "Não farmou nada 📉",
  "Errou feio bb 😬",
  "Foi no chute mesmo, né?",
  "Aura -100 😭",
];

const mensagensDeDesenpenho = [
  "🚀 Voou alto! Velocidade recorde!",
  "⚡ Meio rápido, mas ainda assim impecável!",
  "🎉 Parabéns, demorou mas ganhou!",
];

const tabuleiroEl = document.getElementById("tabuleiro");
const contadorJogadasEl = document.getElementById("contador-jogadas");
const contadorParesEl = document.getElementById("contador-pares");
const contadorTempoEl = document.getElementById("contador-tempo");
const telaVitoriaEl = document.getElementById("tela-vitoria");
const resumoVitoriaEl = document.getElementById("resumo-vitoria");
const btnReiniciar = document.getElementById("btn-reiniciar");
const btnJogarNovamente = document.getElementById("btn-jogar-novamente");
const mensagemJogadaEl = document.getElementById("mensagem-jogada");

//mensagem pós vitoria
const mensagemDesenpenho = document.getElementById("msgVitoria");
//TENDI PORRA NENHUMA DISSO
function embaralhar(array) {
  for (let i = array.length - 1; i > 0; i--) {
    let j = Math.floor(Math.random() * (i + 1));

    let temp = array[i];
    array[i] = array[j];
    array[j] = temp;
  }
  return array;
}

function mostrarMensagem(texto) {
  mensagemJogadaEl.textContent = texto;

  mensagemJogadaEl.classList.remove("anim");
  void mensagemJogadaEl.offsetWidth; // reinicia a animação CSS
  mensagemJogadaEl.classList.add("anim");
}

function criarConfetes() {
  const emojisConfete = ["💎", "🟩", "🟫", "⛏️", "🌟"];

  for (let i = 0; i < 40; i++) {
    const confete = document.createElement("div");
    confete.classList.add("confete");
    confete.textContent =
      emojisConfete[Math.floor(Math.random() * emojisConfete.length)];

    confete.style.left = Math.random() * 100 + "vw";

    const duracao = 2 + Math.random() * 2;
    confete.style.animationDuration = duracao + "s";
    confete.style.animationDelay = Math.random() * 0.6 + "s";

    document.body.appendChild(confete);

    setTimeout(
      function () {
        confete.remove();
      },
      (duracao + 1) * 1000,
    );
  }
}

function criarBaralho() {
  let cartas = [];

  for (let i = 0; i < listaImagens.length; i++) {
    cartas.push(listaImagens[i]);
    cartas.push(listaImagens[i]);
  }

  cartas = embaralhar(cartas);
  return cartas;
}

function criarTabuleiro() {
  tabuleiroEl.innerHTML = "";

  for (let i = 0; i < baralho.length; i++) {
    const caminhoImagem = baralho[i];

    const carta = document.createElement("div");
    carta.classList.add("carta");
    carta.setAttribute("data-imagem", caminhoImagem);
    carta.setAttribute("data-indice", i);

    carta.style.animationDelay = i * 0.05 + "s";

    const cartaInterna = document.createElement("div");
    cartaInterna.classList.add("carta-interna");

    const cartaFrente = document.createElement("div");
    cartaFrente.classList.add("carta-frente");
    cartaFrente.textContent = "❓";

    const cartaVerso = document.createElement("div");
    cartaVerso.classList.add("carta-verso");

    const imagemCarta = document.createElement("img");
    imagemCarta.src = caminhoImagem;
    imagemCarta.alt = "Imagem da carta";
    imagemCarta.classList.add("imagem-carta");
    cartaVerso.appendChild(imagemCarta);

    cartaInterna.appendChild(cartaFrente);
    cartaInterna.appendChild(cartaVerso);
    carta.appendChild(cartaInterna);

    carta.addEventListener("click", function () {
      virarCarta(carta);
    });

    tabuleiroEl.appendChild(carta);
  }
}

function virarCarta(carta) {
  if (tabuleiroTravado) {
    return;
  }

  if (carta === cartaSelecionada1) {
    return;
  }

  if (carta.classList.contains("encontrada")) {
    return;
  }

  carta.classList.add("virada");

  if (cartaSelecionada1 === null) {
    cartaSelecionada1 = carta;
  } else {
    cartaSelecionada2 = carta;
    totalJogadas++;
    atualizarPainel();
    verificarPar();
  }
}

function verificarPar() {
  const imagem1 = cartaSelecionada1.getAttribute("data-imagem");
  const imagem2 = cartaSelecionada2.getAttribute("data-imagem");

  // distância entre as posições das duas cartas no tabuleiro
  const indice1 = Number(cartaSelecionada1.getAttribute("data-indice"));
  const indice2 = Number(cartaSelecionada2.getAttribute("data-indice"));
  const distancia = Math.abs(indice1 - indice2);

  if (imagem1 === imagem2) {
    cartaSelecionada1.classList.add("encontrada");
    cartaSelecionada2.classList.add("encontrada");

    const mensagem =
      mensagensAcerto[Math.floor(Math.random() * mensagensAcerto.length)];
    mostrarMensagem(mensagem);

    paresEncontrados++;
    atualizarPainel();
    limparSelecao();

    if (paresEncontrados === totalPares) {
      vencerJogo();
    }
  } else {
    let mensagem;
    if (distancia === 1) {
      mensagem =
        mensagensErroPerto[
          Math.floor(Math.random() * mensagensErroPerto.length)
        ];
    } else {
      mensagem =
        mensagensErroLonge[
          Math.floor(Math.random() * mensagensErroLonge.length)
        ];
    }
    mostrarMensagem(mensagem);

    tabuleiroTravado = true;

    setTimeout(function () {
      cartaSelecionada1.classList.remove("virada");
      cartaSelecionada2.classList.remove("virada");
      limparSelecao();
      tabuleiroTravado = false;
    }, 900);
  }
}

function limparSelecao() {
  cartaSelecionada1 = null;
  cartaSelecionada2 = null;
}

function atualizarPainel() {
  contadorJogadasEl.textContent = totalJogadas;
  contadorParesEl.textContent = paresEncontrados + " / " + totalPares;
}

function iniciarTimer() {
  segundosDecorridos = 0;
  atualizarTempoNaTela();

  idIntervaloTempo = setInterval(function () {
    segundosDecorridos++;
    atualizarTempoNaTela();
  }, 1000);
}

function pararTimer() {
  clearInterval(idIntervaloTempo);
}

function atualizarTempoNaTela() {
  let minutos = Math.floor(segundosDecorridos / 60);
  let segundos = segundosDecorridos % 60;

  let minutosTexto;
  if (minutos < 10) {
    minutosTexto = "0" + minutos;
  } else {
    minutosTexto = minutos;
  }

  let segundosTexto;
  if (segundos < 10) {
    segundosTexto = "0" + segundos;
  } else {
    segundosTexto = segundos;
  }

  contadorTempoEl.textContent = minutosTexto + ":" + segundosTexto;
}

function vencerJogo() {
  pararTimer();
  if (segundosDecorridos >= 1 && segundosDecorridos <= 30) {
    mensagemDesenpenho.textContent = mensagensDeDesenpenho[0];
  }
  else if (segundosDecorridos >= 31 && segundosDecorridos <= 59 ) {
    mensagemDesenpenho.textContent = mensagensDeDesenpenho[1];
  }
  else if (segundosDecorridos >= 60) {
    mensagemDesenpenho.textContent = mensagensDeDesenpenho[2];
  }
  
    resumoVitoriaEl.textContent =
    "Você fez " +
    totalJogadas +
    " jogadas e levou " +
    contadorTempoEl.textContent +
    ".";

  telaVitoriaEl.classList.remove("escondido");

  somVitoria.play();
  criarConfetes();
}

function iniciarJogo() {
  totalJogadas = 0;
  paresEncontrados = 0;
  tabuleiroTravado = false;
  limparSelecao();
  atualizarPainel();
  mostrarMensagem("Bora começar! 🎮");

  telaVitoriaEl.classList.add("escondido");

  baralho = criarBaralho();
  criarTabuleiro();

  pararTimer();
  iniciarTimer();

  somInicio.play().catch(function () {
    console.log("Áudio será liberado após o primeiro clique do jogador.");
  });
}

btnReiniciar.addEventListener("click", iniciarJogo);
btnJogarNovamente.addEventListener("click", iniciarJogo);

iniciarJogo();
